mapper.select:
select mainClassifyCH,primaryClassifyCode,primaryClassifyCH,SECONDARYCLASSIFYCODE,SECONDARYCLASSIFYCH from ( select * from ( select #{mainClassifyCh} as mainClassifyCH ,CODEID as primaryClassifyCode,CODETEXT as primaryClassifyCH from V_CLASSIFY_INFO
CODETEXT like #{primaryClassifyCh}||'%'
)a INNER join (select CODEID as SECONDARYCLASSIFYCODE,CODETEXT as SECONDARYCLASSIFYCH,PARCODEID from V_CLASSIFY_INFO )b on a.PRIMARYCLASSIFYCODE = b.PARCODEID or a.PRIMARYCLASSIFYCODE = b.SECONDARYCLASSIFYCODE )
